": {"VarKey": null, "Value": "$=
string op = {config}["operation"].ToString();
string text = {selectedText};
string result;

switch (op)
{
    case "转大写":
        result = text.ToUpper();
        break;
    case "转小写":
        result = text.ToLower();
        break;
    case "首字母大写":
        result = char.ToUpper(text[0]) + text.Substring(1);
        break;
    case "反转文本":
        var chars = text.ToCharArray();
        System.Array.Reverse(chars);
        result = new string(chars);
        break;
    case "Base64编码":
        result = Convert.ToBase64String(Encoding.UTF8.GetBytes(text));
        break;
    case "Base64解码":
        try { result = Encoding.UTF8.GetString(Convert.FromBase64String(text)); }
        catch { result = "Base64解码失败，请检查输入。"; }
        break;
    default:
        result = text;
        break;
}

